// ==UserScript==
// @name         WoozyCheats (Tsunami)
// @version      0.0
// @description  easy to celebrate
// @author       Cyclone/Sparky
// @Participants WindowsX/Shizmi
// @match        https://*.tankionline.com/*
// @match        https://tankionline.com/play/
// @match        https://3dtank.com/*
// @grant        GM_setValue
// @grant        GM_getValue
// @grant        GM_registerMenuCommand
// @run-at       document-idle
// ==/UserScript==






(function() {
    "use strict";
    const defaultConfig = {
        menu: {
            toggleKey: "0"
        },
        chat: {
            isOpen: true
        },
        tsunamiReload: {
            status: false,
            bullets: 25,
            hotkey: "K"
        }
    };
    let config = GM_getValue("woozyMenuConfig", null);
    if (!config) {
        config = defaultConfig;
        saveConfig()
    } else {
        config.menu = config.menu || {
            toggleKey: "0"
        };
        config.chat = config.chat || {
            isOpen: true
        };
        config.tsunamiReload = config.tsunamiReload || defaultConfig.tsunamiReload
    }

    function syncConfigToPage() {
        const snapshot = JSON.parse(JSON.stringify(config));
        try {
            unsafeWindow.Config = snapshot;
            unsafeWindow.dispatchEvent(new CustomEvent("woozyConfigUpdated", {
                detail: snapshot
            }))
        } catch (e) {
            window.Config = snapshot;
            window.dispatchEvent(new CustomEvent("woozyConfigUpdated", {
                detail: snapshot
            }))
        }
    }

    function saveConfig() {
        GM_setValue("woozyMenuConfig", config);
        syncConfigToPage()
    }
    syncConfigToPage();
    const style = document.createElement("style");
    style.textContent = `
    #woozy-menu {
      position: fixed;
      top: 80px;
      left: 80px;
      width: 300px;
      background: #14161b;
      border: 1px solid #262932;
      border-radius: 10px;
      box-shadow: 0 12px 32px rgba(0,0,0,0.5);
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Arial, sans-serif;
      color: #c7cbd1;
      z-index: 999999;
      user-select: none;
      overflow: hidden;
    }
    #woozy-menu * { box-sizing: border-box; }

    #woozy-header {
      background: #191c22;
      padding: 12px 14px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      cursor: grab;
      border-bottom: 1px solid #262932;
    }
    #woozy-header.dragging { cursor: grabbing; }
    #woozy-title {
      display: flex;
      align-items: center;
      gap: 8px;
    }
    #woozy-title .dot {
      width: 6px; height: 6px;
      border-radius: 50%;
      background: #4d90fe;
    }
    #woozy-title .label {
      font-size: 12px;
      font-weight: 600;
      letter-spacing: 1.5px;
      color: #e4e6eb;
    }
    #woozy-header .close-btn {
      cursor: pointer;
      color: #565b66;
      font-size: 13px;
      line-height: 1;
      padding: 2px 4px;
      border-radius: 4px;
      transition: color .15s, background .15s;
    }
    #woozy-header .close-btn:hover { color: #c7cbd1; background: #262932; }

    #woozy-tabs {
      display: flex;
      background: #14161b;
      border-bottom: 1px solid #262932;
    }
    .woozy-tab {
      flex: 1;
      text-align: center;
      padding: 9px 0;
      font-size: 11px;
      font-weight: 500;
      letter-spacing: .5px;
      cursor: pointer;
      color: #6b7078;
      transition: color .15s, background .15s;
      position: relative;
    }
    .woozy-tab:hover { color: #9aa0aa; }
    .woozy-tab.active {
      color: #4d90fe;
    }
    .woozy-tab.active::after {
      content: '';
      position: absolute;
      left: 0; right: 0; bottom: -1px;
      height: 2px;
      background: #4d90fe;
    }

    #woozy-body { padding: 16px; }
    .woozy-panel { display: none; }
    .woozy-panel.active { display: block; }

    .field {
      margin-bottom: 4px;
    }
    .field-row {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 10px 0;
    }
    .field-label {
      font-size: 12.5px;
      color: #c7cbd1;
      font-weight: 500;
    }
    .field-sub {
      font-size: 10.5px;
      color: #565b66;
      margin-top: 1px;
    }

    /* switch */
    .switch {
      position: relative;
      width: 38px;
      height: 20px;
      background: #2a2e37;
      border-radius: 20px;
      cursor: pointer;
      transition: background .18s ease;
      flex-shrink: 0;
    }
    .switch.on { background: #315a9c; }
    .switch .knob {
      position: absolute;
      top: 2px; left: 2px;
      width: 16px; height: 16px;
      background: #8b909a;
      border-radius: 50%;
      transition: left .18s ease, background .18s ease;
    }
    .switch.on .knob { left: 20px; background: #4d90fe; }

    /* slider section (collapsible) */
    #bullets-section {
      overflow: hidden;
      max-height: 0;
      opacity: 0;
      transition: max-height .22s ease, opacity .18s ease, margin .22s ease;
      margin-top: 0;
    }
    #bullets-section.open {
      max-height: 80px;
      opacity: 1;
      margin-top: 4px;
    }
    .slider-header {
      display: flex;
      justify-content: space-between;
      align-items: baseline;
      margin-bottom: 8px;
    }
    .slider-header .field-label { font-size: 11.5px; color: #9aa0aa; font-weight: 500; }
    .slider-value {
      font-family: 'SF Mono', Consolas, monospace;
      font-size: 12px;
      color: #4d90fe;
      background: #1c2733;
      padding: 1px 7px;
      border-radius: 4px;
    }
    input[type=range] {
      -webkit-appearance: none;
      appearance: none;
      width: 100%;
      height: 4px;
      border-radius: 4px;
      margin: 6px 0 14px 0;
      cursor: pointer;
    }
    input[type=range]::-webkit-slider-thumb {
      -webkit-appearance: none;
      width: 14px; height: 14px;
      border-radius: 50%;
      background: #e4e6eb;
      border: 2px solid #4d90fe;
      cursor: pointer;
      margin-top: 0;
      box-shadow: 0 1px 4px rgba(0,0,0,0.4);
    }
    input[type=range]::-moz-range-thumb {
      width: 12px; height: 12px;
      border-radius: 50%;
      background: #e4e6eb;
      border: 2px solid #4d90fe;
      cursor: pointer;
    }
    input[type=range]::-moz-range-track {
      height: 4px;
      border-radius: 4px;
      background: #2a2e37;
    }

    .divider {
      height: 1px;
      background: #21242b;
      margin: 2px 0;
    }

    /* hotkeys tab */
    .hotkey-row {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 11px 0;
      border-bottom: 1px solid #1d2027;
    }
    .hotkey-row:last-of-type { border-bottom: none; }
    .hotkey-input {
      background: #1c1f26;
      border: 1px solid #2a2e37;
      color: #c7cbd1;
      padding: 5px 12px;
      border-radius: 6px;
      font-family: 'SF Mono', Consolas, monospace;
      font-size: 11.5px;
      font-weight: 600;
      cursor: pointer;
      min-width: 52px;
      text-align: center;
      outline: none;
      caret-color: transparent;
      transition: border-color .15s, color .15s;
    }
    .hotkey-input:hover { border-color: #3a3f4b; }
    .hotkey-input.listening {
      border-color: #4d90fe;
      color: #4d90fe;
      animation: blink 1s infinite;
    }
    @keyframes blink {
      0%,100% { opacity: 1; }
      50% { opacity: .4; }
    }
    .hint {
      font-size: 10.5px;
      color: #565b66;
      margin-top: 10px;
      line-height: 1.5;
    }

    /* toasts */
    #woozy-toast-container {
      position: fixed;
      bottom: 28px;
      right: 28px;
      z-index: 9999999;
      display: flex;
      flex-direction: column;
      gap: 6px;
    }
    .woozy-toast {
      background: #16181d;
      border: 1px solid #262932;
      border-left: 3px solid #4d90fe;
      color: #c7cbd1;
      padding: 9px 14px;
      border-radius: 6px;
      font-size: 12px;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Arial, sans-serif;
      box-shadow: 0 6px 18px rgba(0,0,0,0.4);
      opacity: 0;
      transform: translateX(16px);
      transition: all .2s ease;
    }
    .woozy-toast.show { opacity: 1; transform: translateX(0); }
    .woozy-toast.off { border-left-color: #6b7078; }
  `;
    document.head.appendChild(style);
    const toastContainer = document.createElement("div");
    toastContainer.id = "woozy-toast-container";
    document.body.appendChild(toastContainer);

    function showToast(message, isOn) {
        const toast = document.createElement("div");
        toast.className = "woozy-toast" + (isOn ? "" : " off");
        toast.textContent = message;
        toastContainer.appendChild(toast);
        requestAnimationFrame(() => toast.classList.add("show"));
        setTimeout(() => {
            toast.classList.remove("show");
            setTimeout(() => toast.remove(), 250)
        }, 2400)
    }
    const menu = document.createElement("div");
    menu.id = "woozy-menu";
    menu.innerHTML = `
    <div id="woozy-header">
      <div id="woozy-title">
        <span class="dot"></span>
        <span class="label">WOOZY</span>
      </div>
      <span class="close-btn" title="Hide menu">✕</span>
    </div>
    <div id="woozy-tabs">
      <div class="woozy-tab active" data-tab="main">Main</div>
      <div class="woozy-tab" data-tab="hotkeys">Hotkeys</div>
    </div>
    <div id="woozy-body">
      <div class="woozy-panel active" data-panel="main">
        <div class="field">
          <div class="field-row">
            <div>
              <div class="field-label">Tsunami Reload</div>
              <div class="field-sub">Rapid reload override</div>
            </div>
            <div class="switch" id="tsunami-switch"><div class="knob"></div></div>
          </div>
          <div id="bullets-section">
            <div class="slider-header">
              <span class="field-label">Bullets</span>
              <span class="slider-value" id="bullets-value">${config.tsunamiReload.bullets}</span>
            </div>
            <input type="range" id="bullets-slider" min="1" max="100" value="${config.tsunamiReload.bullets}">
          </div>
        </div>
      </div>
      <div class="woozy-panel" data-panel="hotkeys">
        <div class="hotkey-row">
          <div class="field-label">Toggle Tsunami Reload</div>
          <input class="hotkey-input" id="tsunami-hotkey" readonly value="${config.tsunamiReload.hotkey}">
        </div>
        <div class="hotkey-row">
          <div class="field-label">Show / Hide Menu</div>
          <input class="hotkey-input" id="menu-hotkey" readonly value="${config.menu.toggleKey}">
        </div>
        <div class="hint">Click a key field, then press any key to rebind it.</div>
      </div>
    </div>
  `;
    document.body.appendChild(menu);
    (function makeDraggable() {
        const header = menu.querySelector("#woozy-header");
        let offsetX = 0,
            offsetY = 0,
            dragging = false;
        header.addEventListener("mousedown", e => {
            if (e.target.classList.contains("close-btn")) return;
            dragging = true;
            header.classList.add("dragging");
            offsetX = e.clientX - menu.offsetLeft;
            offsetY = e.clientY - menu.offsetTop
        });
        document.addEventListener("mousemove", e => {
            if (!dragging) return;
            menu.style.left = e.clientX - offsetX + "px";
            menu.style.top = e.clientY - offsetY + "px"
        });
        document.addEventListener("mouseup", () => {
            dragging = false;
            header.classList.remove("dragging")
        })
    })();
    menu.querySelectorAll(".woozy-tab").forEach(tab => {
        tab.addEventListener("click", () => {
            menu.querySelectorAll(".woozy-tab").forEach(t => t.classList.remove("active"));
            menu.querySelectorAll(".woozy-panel").forEach(p => p.classList.remove("active"));
            tab.classList.add("active");
            menu.querySelector(`.woozy-panel[data-panel="${tab.dataset.tab}"]`).classList.add("active")
        })
    });
    menu.querySelector(".close-btn").addEventListener("click", () => {
        menu.style.display = "none"
    });

    function toggleMenuVisibility() {
        menu.style.display = menu.style.display === "none" ? "block" : "none"
    }
    const tsunamiSwitch = menu.querySelector("#tsunami-switch");
    const bulletsSection = menu.querySelector("#bullets-section");

    function setTsunamiReload(on, viaHotkey) {
        config.tsunamiReload.status = on;
        saveConfig();
        tsunamiSwitch.classList.toggle("on", on);
        bulletsSection.classList.toggle("open", on);
        showToast(`Tsunami Reload ${on?"enabled":"disabled"}${viaHotkey?" · hotkey":""}`, on)
    }
    if (config.tsunamiReload.status) {
        tsunamiSwitch.classList.add("on");
        bulletsSection.classList.add("open")
    }
    tsunamiSwitch.addEventListener("click", () => {
        setTsunamiReload(!config.tsunamiReload.status, false)
    });
    const slider = menu.querySelector("#bullets-slider");
    const sliderValueLabel = menu.querySelector("#bullets-value");

    function updateSliderFill(val) {
        const pct = (val - 1) / 99 * 100;
        slider.style.background = `linear-gradient(90deg, #4d90fe 0%, #4d90fe ${pct}%, #2a2e37 ${pct}%, #2a2e37 100%)`
    }
    updateSliderFill(config.tsunamiReload.bullets);
    slider.addEventListener("input", () => {
        const val = parseInt(slider.value, 10);
        config.tsunamiReload.bullets = val;
        sliderValueLabel.textContent = val;
        updateSliderFill(val);
        saveConfig()
    });
    let listeningFor = null;

    function startListening(inputEl, which) {
        listeningFor = which;
        inputEl.classList.add("listening");
        inputEl.value = "..."
    }

    function stopListening(inputEl, keyName) {
        inputEl.classList.remove("listening");
        inputEl.value = keyName;
        listeningFor = null
    }
    const tsunamiHotkeyInput = menu.querySelector("#tsunami-hotkey");
    const menuHotkeyInput = menu.querySelector("#menu-hotkey");
    tsunamiHotkeyInput.addEventListener("click", () => startListening(tsunamiHotkeyInput, "tsunami"));
    menuHotkeyInput.addEventListener("click", () => startListening(menuHotkeyInput, "menu"));
    document.addEventListener("keydown", e => {
        if (listeningFor) {
            if (["Shift", "Control", "Alt", "Meta"].includes(e.key)) return;
            e.preventDefault();
            const keyName = e.key.length === 1 ? e.key.toUpperCase() : e.key;
            if (listeningFor === "tsunami") {
                config.tsunamiReload.hotkey = keyName;
                stopListening(tsunamiHotkeyInput, keyName);
                showToast(`Tsunami Reload hotkey set to ${keyName}`, true)
            } else if (listeningFor === "menu") {
                config.menu.toggleKey = keyName;
                stopListening(menuHotkeyInput, keyName);
                showToast(`Menu hotkey set to ${keyName}`, true)
            }
            saveConfig();
            return
        }
        if (!config.chat.isOpen) return;
        const tag = document.activeElement.tagName;
        if (tag === "INPUT" || tag === "TEXTAREA") return;
        const keyName = e.key.length === 1 ? e.key.toUpperCase() : e.key;
        if (keyName === config.tsunamiReload.hotkey) {
            setTsunamiReload(!config.tsunamiReload.status, true)
        } else if (keyName === config.menu.toggleKey) {
            toggleMenuVisibility()
        }
    });

    function setChatOpen(isOpen) {
        config.chat.isOpen = !!isOpen;
        saveConfig()
    }
    try {
        unsafeWindow.WoozySetChatOpen = setChatOpen
    } catch (e) {
        window.WoozySetChatOpen = setChatOpen
    }
    GM_registerMenuCommand("Toggle Woozy Menu", toggleMenuVisibility)
})();



